function getDateLabel(inputDate) {
    const today = new Date()
    const tomm = new Date()
    tomm.setDate(tomm.getDate() + 1)

    today.setHours(0, 0, 0, 0)
    tomm.setHours(0, 0, 0, 0)
    inputDate.setHours(0, 0, 0, 0)

    if (today.getTime() === inputDate.getTime()) {
        return 'Today'
    } else if (tomm.getTime() === inputDate.getTime()) {
        return 'Tommorrow'
    } else {
        return inputDate.toLocaleDateString(('en-US'), { month: 'short', day: 'numeric', year: 'numeric' })
    }
}
export function calculateInstallments(total, duration) {
    // write installments logic here
    const startDate = new Date()
    const date = new Date(startDate)
    const emi = Number((Number(total) / Number(duration)).toFixed(2))
    return Array.from({ length: duration }, (_, i) => {
        const dueDate = date.setMonth(date.getMonth + i)
        return {
            id: `${dueDate}_i`,
            dueDate,
            dueDateLabel: getDateLabel(dueDate),
            installment: emi
        }
    })
}
